737: // removeNonPersistedProperties removes non-persisted dashboard properties
738: func removeNonPersistedProperties(dashboard map[string]interface{}) {
739: 	nonPersistedProperties := map[string]bool{
740: 		"events":                           true,
741: 		"meta":                             true,
742: 		"panels":                           true, // handled specially below
743: 		"templating":                       true, // handled specially below
744: 		"originalTime":                     true,
745: 		"originalTemplating":               true,
746: 		"originalLibraryPanels":            true,
747: 		"panelInEdit":                      true,
748: 		"panelInView":                      true,
749: 		"getVariablesFromState":            true,
750: 		"formatDate":                       true,
751: 		"appEventsSubscription":            true,
752: 		"panelsAffectedByVariableChange":   true,
753: 		"lastRefresh":                      true,
754: 		"timeRangeUpdatedDuringEditOrView": true,
755: 		"originalDashboard":                true,
756: 	}
