951: // applyPanelAutoMigration applies the same auto-migration logic as the frontend PanelModel constructor
952: func applyPanelAutoMigration(panel map[string]interface{}) {
953: 	panelType, ok := panel["type"].(string)
954: 	if !ok {
955: 		return
956: 	}
957: 
958: 	// Graph needs special logic as it can be migrated to multiple panels
959: 	// Including graphite which was previously migrated to graph in the schema version 2 migration in DashboardMigrator.ts
960: 	// but this was a bug because in there graphite was set to graph, but since those migrations run
961: 	// after PanelModel.restoreModel where autoMigrateFrom is set, this caused the graph migration to be skipped.
962: 	// And this resulted in a dashboard with invalid panels.
963: 	newType := schemaversion.GetAngularPanelMigration(panelType, panel)
964: 
965: 	// Apply auto-migration if a new type was determined
966: 	if newType != "" {
967: 		panel["autoMigrateFrom"] = panelType
968: 		panel["type"] = newType
969: 	}
970: }
