978: // removeNullValuesRecursivelyWithContext removes null values from nested objects and arrays
979: // This matches the frontend's JSON.stringify/parse behavior in getSaveModelClone()
980: func removeNullValuesRecursivelyWithContext(data interface{}, panelType string) {
981: 	switch v := data.(type) {
982: 	case map[string]interface{}:
983: 		// Remove null values from map
984: 		for key, value := range v {
985: 			if value == nil {
986: 				// Frontend removes null values via JSON serialization, so we should too
987: 				// No special case needed for threshold steps
988: 				delete(v, key)
989: 			} else {
990: 				// Recursively process nested values
991: 				removeNullValuesRecursivelyWithContext(value, panelType)
992: 			}
993: 		}
994: 	case []interface{}:
995: 		// Process array elements
996: 		for _, item := range v {
997: 			if item != nil {
998: 				removeNullValuesRecursivelyWithContext(item, panelType)
999: 			}
1000: 		}
1001: 	}
1002: }
